        self.val = x
        self.left = None
        self.right = None

class Solution:
    def __init__(self):
        self.queue = deque()
    def deleteNode(self, root, val):
        if not root:
            return False
        if root.val == val:
            return True
        self.queue.append(root)
        while self.queue:
            node = self.queue.popleft()
            if node.left:
                self.queue.append(node.left)
            if node.right:
                self.queue.append(node.right)
        return False

